}
.editor-heading-h3 {
    margin: 0.7rem 0 0.35rem;
    font-size: 1.15rem;
    font-weight: 600;
    line-height: 1.35;
    color: var(--text-heading);
}
.editor-quote {
    margin: 0.5rem 0;
    padding: 0.3rem 0.65rem;
    border-left: 2px solid var(--editor-accent);
    background: color-mix(in srgb, var(--editor-accent) 5%, transparent);
    color: var(--editor-text);
    font-style: italic;
}

/* ── Footer bar (word count + save status + buttons) ── */
.editor-footer {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.5rem 0;
    border-top: 1px solid var(--editor-border);
    margin-top: auto;
    gap: 0.5rem;
}
.editor-footer-left {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    min-width: 0;
}
.editor-footer-actions {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    flex-shrink: 0;
}
.editor-word-count {
    font-size: 0.8rem;
    color: var(--text-muted);
    user-select: none;
    padding-left: 0.25rem;
    white-space: nowrap;
}
.editor-save-status {
    font-size: 0.75rem;
    user-select: none;
    white-space: nowrap;
}
.editor-save-status--saving {
    color: var(--text-muted);
}
.editor-save-status--saved {
    color: var(--text-muted);
}
.editor-save-status--unsaved {
    color: var(--accent-amber, #d4a017);
}

/* ── Bar loader positioning ── */
.editor-loader-wrapper {
    height: 4px;
    flex-shrink: 0;
}

/* ── Save button ── */
.editor-save-bttn {
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0.5rem 1.25rem;
    border-radius: 15px;
    background-color: var(--editor-accent);
    color: #ffffff;
    font-weight: 650;
    cursor: pointer;
    border: none;
    transition: background-color 0.15s ease, transform 0.1s ease, opacity 0.15s ease;
}
.editor-save-bttn:hover {
    opacity: 0.9;
}
.editor-save-bttn:active {
    transform: scale(0.98);
}
.editor-save-bttn:focus {
    outline: none;
}
.editor-save-bttn-disabled {
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0.5rem 1.25rem;
    border-radius: 15px;
    background-color: var(--bg-pill);
    color: var(--text-muted);
    font-weight: 650;
    user-select: none;
    border: none;
    cursor: not-allowed;
}
