    outline: none;
}

/* ── Draft button ── */
.editor-draft-bttn {
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0.5rem 1rem;
    border-radius: 15px;
    background-color: transparent;
    color: var(--editor-text);
    font-weight: 600;
    cursor: pointer;
    border: 1.5px solid var(--editor-border);
    transition: background-color 0.15s ease, border-color 0.15s ease, transform 0.1s ease;
    font-size: 0.875rem;
}
.editor-draft-bttn:hover {
    background-color: var(--bg-pill);
    border-color: var(--text-muted);
}
.editor-draft-bttn:active {
    transform: scale(0.98);
}
.editor-draft-bttn:focus {
    outline: none;
}
.editor-draft-bttn-disabled {
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0.5rem 1rem;
    border-radius: 15px;
    background-color: transparent;
    color: var(--text-muted);
    font-weight: 600;
    border: 1.5px solid var(--editor-border);
    cursor: not-allowed;
    opacity: 0.5;
    font-size: 0.875rem;
}
.editor-draft-bttn-disabled:focus {
    outline: none;
}

/* ── Image upload icon (inside toolbar) ── */
.editor-upload-image-icon {
    padding: 0.4rem;
    border-radius: 6px;
    cursor: pointer;
    transition: all 0.15s ease;
}
.editor-upload-image-icon:hover {
    background-color: var(--bg-pill);
}

/* ── Image components ── */
.image-container {
    display: flex;
    justify-content: center;
    width: 100%;
    height: fit-content;
}
.image-wrapper {
    position: relative;
    display: flex;
    justify-content: flex-end;
    margin: 1rem 0;
    width: fit-content;
    height: fit-content;
}
.image-actions {
    position: absolute;
    display: flex;
    gap: 0.3rem;
    top: 0;
    right: 0;
    margin: 0.5rem;
    z-index: 11;
}
.image-action-btn {
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 0.4rem;
    border-radius: 50%;
    cursor: pointer;
    transition: ease-in-out 0.1s;
    background-color: rgba(0, 0, 0, 0.35);
}
.image-action-btn:hover {
    background-color: rgba(0, 0, 0, 0.55);
}
.dimension-display {
    position: absolute;
    display: flex;
    justify-content: center;
    align-items: center;
    top: -35px;
    left: 50%;
    transform: translateX(-50%);
    background-color: var(--bg-pill);
    color: var(--text-muted);
    padding: 0.4rem 0.5rem;
    white-space: nowrap;
    pointer-events: none;
    font-size: 0.8rem;
    border-radius: 4px;
}

/* ── Resize handles ── */
.southeast-side-handle {
    position: absolute;
    bottom: -4px;
    right: -4px;
    width: 12px;
    height: 12px;
    background-color: var(--bg-pill);
    border: 1px solid var(--editor-text);
    border-radius: 50%;
    cursor: nwse-resize;
    z-index: 10;
}
.southwest-side-handle {
    position: absolute;
    bottom: -4px;
    left: -4px;
    width: 12px;
    height: 12px;
    background-color: var(--bg-pill);
    border: 1px solid var(--editor-text);
    border-radius: 50%;
    cursor: nesw-resize;
    z-index: 10;
}
.northeast-side-handle {
    position: absolute;
    top: -4px;
    right: -4px;
    width: 12px;
    height: 12px;
    background-color: var(--bg-pill);
    border: 1px solid var(--editor-text);
    border-radius: 50%;
    cursor: sw-resize;
    z-index: 10;
}
.northwest-side-handle {
    position: absolute;
    top: -4px;
    left: -4px;
    width: 12px;
    height: 12px;
    background-color: var(--bg-pill);
    border: 1px solid var(--editor-text);
    border-radius: 50%;
    cursor: se-resize;
    z-index: 10;
}
.east-side-handle {
    position: absolute;
    top: 50%;
    right: -4px;
    width: 8px;
    height: 20px;
    background-color: var(--bg-pill);
    border: 1px solid var(--editor-text);
    border-radius: 2px;
    transform: translateY(-50%);
    cursor: ew-resize;
    z-index: 10;
}
.south-side-handle {
    position: absolute;
    bottom: -4px;
    left: 50%;
    width: 20px;
    height: 8px;
    background-color: var(--bg-pill);
    border: 1px solid var(--editor-text);
    border-radius: 2px;
    transform: translateX(-50%);
    cursor: ns-resize;
    z-index: 10;
}
.north-side-handle {
    position: absolute;
    top: -4px;
    left: 50%;
    width: 20px;
    height: 8px;
    background-color: var(--bg-pill);
    border: 1px solid var(--editor-text);
    border-radius: 2px;
    transform: translateX(-50%);
    cursor: nw-resize;
    z-index: 10;
}

/* ── Image loading overlay ── */
.image-loading-overlay {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    background-color: rgba(0, 0, 0, 0.45);
    border-radius: 5px;
    gap: 8px;
    pointer-events: none;
}
.image-loading-spinner {
    width: 28px;
    height: 28px;
    border: 3px solid rgba(255, 255, 255, 0.2);
    border-top: 3px solid var(--editor-accent);
    border-radius: 50%;
    animation: image-spin 0.8s linear infinite;
}
@keyframes image-spin {
    0% { transform: rotate(0deg); }
    100% { transform: rotate(360deg); }
}

/* ── Full-screen image view ── */
.image-view {
    position: fixed;
    top: 0;
    left: 0;
    width: 100vw;
    height: 100vh;
    object-fit: contain;
    background: rgba(0, 0, 0, 0.7);
    z-index: 9999;
    cursor: zoom-out;
    box-sizing: border-box;
}

/* ── Close confirmation dialog ── */
.editor-close-confirm-overlay {
    position: absolute;
    inset: 0;
    display: flex;
    justify-content: center;
    align-items: center;
    background-color: rgba(0, 0, 0, 0.4);
    backdrop-filter: blur(4px);
    border-radius: 16px;
    z-index: 20;
    cursor: pointer;
}
.editor-close-confirm-card {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 1.25rem;
    padding: 1.5rem 2rem;
    background-color: var(--editor-bg);
    border: 1px solid var(--editor-border);
    border-radius: 14px;
    box-shadow: var(--shadow-modal);
    max-width: 320px;
    width: 90%;
    cursor: default;
}
.editor-close-confirm-message {
    margin: 0;
    font-size: 1rem;
    font-weight: 600;
    color: var(--editor-text);
    text-align: center;
    line-height: 1.4;
}
.editor-close-confirm-actions {
    display: flex;
    gap: 0.75rem;
    width: 100%;
}
.editor-close-confirm-discard {
    flex: 1;
    padding: 0.5rem 1rem;
    border-radius: 12px;
    background-color: transparent;
    color: var(--editor-text);
    font-weight: 600;
    font-size: 0.875rem;
    cursor: pointer;
    border: 1.5px solid var(--editor-border);
    transition: background-color 0.15s ease, border-color 0.15s ease;
}
.editor-close-confirm-discard:hover {
    background-color: var(--bg-pill);
    border-color: var(--text-muted);
}
.editor-close-confirm-discard:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}
.editor-close-confirm-save {
    flex: 1;
    padding: 0.5rem 1rem;
    border-radius: 12px;
    background-color: var(--editor-accent);
    color: #ffffff;
    font-weight: 650;
    font-size: 0.875rem;
    cursor: pointer;
    border: none;
    transition: opacity 0.15s ease;
}
.editor-close-confirm-save:hover {
    opacity: 0.9;
}
.editor-close-confirm-save:disabled {
    opacity: 0.6;
    cursor: not-allowed;
}
.editor-close-confirm-error {
    margin: -0.75rem 0 0;
    font-size: 0.8rem;
    color: var(--accent-amber, #d4a017);
    text-align: center;
    line-height: 1.3;
}

/* ── Mobile responsive (overrides only) ── */
@media (max-width: 640px) {
    .editor-parent-container {
        z-index: 132;
    }
    .editor-container {
        width: 95%;
        height: 95%;
        padding: 0.75rem;
        border-radius: 12px;
    }
    .toolbar {
        justify-content: center;
    }
    .toolbar-bttns,
    .is-active {
        padding: 0.35rem;
    }
    .toolbar-bttns svg,
    .is-active svg {
        width: 18px;
        height: 18px;
    }
    .toolbar-divider {
        margin: 0 4px;
        height: 16px;
    }
    .content-title-input {
        font-size: 1.35rem;
    }
    .editor-save-bttn {
        padding: 0.35rem 0.9rem;
        font-size: 0.85rem;
    }
    .editor-save-bttn-disabled {
        padding: 0.35rem 0.9rem;
        font-size: 0.85rem;
    }
    .editor-draft-bttn {
        padding: 0.35rem 0.75rem;
        font-size: 0.8rem;
    }
    .editor-draft-bttn-disabled {
        padding: 0.35rem 0.75rem;
        font-size: 0.8rem;
    }
    .editor-footer-actions {
        gap: 0.35rem;
    }
    .editor-close-confirm-overlay {
        border-radius: 12px;
    }
    .editor-close-confirm-card {
        padding: 1.25rem 1.5rem;
        max-width: 280px;
    }
}

