import { mergeRegister } from '@lexical/utils';

function FloatingSelectionToolbarComponent() {
    const [editor] = useLexicalComposerContext();
    const toolbarRef = useRef(null);
    const [isVisible, setIsVisible] = useState(false);
    const [position, setPosition] = useState({ top: 0, left: 0 });
    const [formats, setFormats] = useState({
        bold: false,
        italic: false,
        underline: false,
        strikethrough: false,
        code: false,
        isLink: false,
    });

    const updateToolbar = useCallback(() => {
        editor.getEditorState().read(() => {
            const selection = $getSelection();
            if (!$isRangeSelection(selection) || selection.isCollapsed()) {
                setIsVisible(false);
                return;
            }

            const nativeSelection = window.getSelection();
            if (!nativeSelection || nativeSelection.rangeCount === 0 || nativeSelection.isCollapsed) {
                setIsVisible(false);
                return;
            }

            const range = nativeSelection.getRangeAt(0);
            const rect = range.getBoundingClientRect();

            if (rect.width === 0 && rect.height === 0) {
                setIsVisible(false);
                return;
            }

            const toolbarWidth = 240;
            const toolbarHeight = 38;
            let top = rect.top + window.scrollY - toolbarHeight - 8;
            let left = rect.left + window.scrollX + (rect.width / 2) - (toolbarWidth / 2);

            // Flip below if near top
            if (top < window.scrollY + 8) {
                top = rect.bottom + window.scrollY + 8;
            }

            // Clamp horizontal
            left = Math.max(8, Math.min(left, window.innerWidth - toolbarWidth - 8));

            setPosition({ top, left });
            setIsVisible(true);

            const node = selection.anchor.getNode();
            const parent = node.getParent();

            setFormats({
                bold: selection.hasFormat('bold'),
                italic: selection.hasFormat('italic'),
                underline: selection.hasFormat('underline'),
                strikethrough: selection.hasFormat('strikethrough'),
                code: selection.hasFormat('code'),
                isLink: $isLinkNode(parent) || $isLinkNode(node),
            });
        });
    }, [editor]);

    useEffect(() => {
        return mergeRegister(
            editor.registerCommand(
                SELECTION_CHANGE_COMMAND,
                () => {
                    updateToolbar();
                    return false;
                },
