async function handleImageFile(file, editor, addUploadedImagePath, token) {
    if (!file || !file.type.startsWith('image/')) return;

    const blobUrl = URL.createObjectURL(file);

    editor.dispatchCommand(INSERT_IMAGE_COMMAND, {
        src: blobUrl,
        width: 500,
        height: 500,
        loading: true,
    });

