    height: 12px;
    background-color: var(--bg-pill);
    border: 1px solid var(--editor-text);
    border-radius: 50%;
    cursor: sw-resize;
    z-index: 10;
}
.northwest-side-handle {
    position: absolute;
    top: -4px;
    left: -4px;
    width: 12px;
    height: 12px;
    background-color: var(--bg-pill);
    border: 1px solid var(--editor-text);
    border-radius: 50%;
    cursor: se-resize;
