}
.east-side-handle {
    position: absolute;
    top: 50%;
    right: -4px;
    width: 8px;
    height: 20px;
    background-color: var(--bg-pill);
    border: 1px solid var(--editor-text);
    border-radius: 2px;
    transform: translateY(-50%);
    cursor: ew-resize;
    z-index: 10;
}
.south-side-handle {
    position: absolute;
    bottom: -4px;
    left: 50%;
    width: 20px;
