    );
};

const ChapterEditor = () => {
    const { storyId, chapterId } = useParams();
    const navigate = useNavigate();
    const { session } = useAuth();
    const token = session?.access_token;

    const { data: chapter, isLoading } = useChapter(storyId, chapterId, token);

    const editorConfig = {
        namespace: 'ChapterEditor',
        theme: EDITOR_THEME,
        nodes: EDITOR_NODES,
        onError(error) {
            console.error('Lexical error:', error);
        },
        editable: true,
    };

    if (isLoading) {
        return (
            <div className="chapter-editor-page">
                <div className="chapter-editor-loading">
                    <BeatLoader size={10} color="var(--text-muted)" />
                </div>
            </div>
        );
    }

    return (
        <motion.div
            className="chapter-editor-page"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ duration: 0.2 }}
        >
            <LexicalComposer initialConfig={editorConfig}>
                <ChapterEditorInner
                    chapter={chapter}
                    storyId={storyId}
                    chapterId={chapterId}
                    token={token}
                    onBack={() => navigate(`/home/stories/${storyId}/manage`)}
                />
            </LexicalComposer>
        </motion.div>
    );
};

export default ChapterEditor;

